    (2, '2026-04-10 14:00:00', '2026-04-10 14:00:00', 1, 1, 1, '배송', '[답변] 배송 일정이 궁금합니다', '현재 주문은 승인 완료 상태이며 택배사 접수 후 운송장이 등록될 예정입니다.', 'COMPLETE', FALSE, 0, NULL, NULL),
