    (4, '2026-04-12 13:20:00', '2026-04-12 13:20:00', NULL, 0, 5, '상품', '재고가 부족한 상품은 다시 입고되나요?', '재고 부족으로 보이는 상품도 재입고 예정인지 문의드립니다.', 'PROCESSING', FALSE, 5, NULL, NULL);

